frappe.ui.form.on('Employee', {
    onload: function(frm) {
        if (frm.is_new() && !frm.doc.employee_number) {
            frm.set_value('employee_number', 'Generating...');

            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Employee',
                    fields: ['employee_number'],
                    filters: [
                        ['employee_number', 'is', 'set'],
                        ['employee_number', '!=', '']
                    ],
                    limit_page_length: 1000
                },
                callback: function(r) {
                    let nextNumber = 1;

                    if (r.message && r.message.length > 0) {
                        // Extract numeric part only, ignoring any prefix (like EMP-)
                        const numbers = r.message.map(e => {
                            const match = e.employee_number.match(/\d+/);
                            return match ? parseInt(match[0]) : 0;
                        });

                        const maxNum = Math.max(...numbers);
                        if (!isNaN(maxNum)) {
                            nextNumber = maxNum + 1;
                        }
                    }

                    // ✅ No prefix, just number
                    frm.set_value('employee_number', nextNumber.toString());
                    console.log("Generated employee number:", nextNumber);
                }
            });
        }
    }
});

frappe.ui.form.on('Employee', {
    department: function(frm) {
        if (frm.doc.department) {
            // Clear subdepartment when department changes
            frm.set_value('custom_subdepartment', '');

            // Fetch subdepartments linked to the selected department
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Subdepartment-Department Mapping',
                    filters: { department_map: frm.doc.department },
                    fields: ['subdepartment_map']
                },
                callback: function(r) {
                    if (r.message && r.message.length > 0) {
                        const subdepartments = r.message.map(d => d.subdepartment_map);

                        // Dynamically filter subdepartment field
                        frm.set_query('custom_subdepartment', function() {
                            return {
                                filters: [['name', 'in', subdepartments]]
                            };
                        });
                    } else {
                        // No matching subdepartments found
                        frm.set_query('custom_subdepartment', function() {
                            return {
                                filters: [['name', '=', '']]
                            };
                        });
                        frappe.msgprint(`No Subdepartments found for Department: ${frm.doc.department}`);
                    }
                }
            });
        } else {
            // Reset query when department is cleared
            frm.set_query('custom_subdepartment', function() {
                return {};
            });
            frm.set_value('custom_subdepartment', '');
        }
    }
});

frappe.ui.form.on('Salary Slip', {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button('Preview One-Third Rule', function() {
                frappe.call({
                    method: "preview_one_third_rule",
                    args: {
                        salary_slip_name: frm.doc.name
                    },
                    callback: function(r) {
                        if (r.message && r.message.status === "success") {
                            frappe.show_alert({
                                message: `Updated Net Pay: ${r.message.net_pay}`,
                                indicator: 'green'
                            });
                            frm.reload_doc();
                        } else {
                            frappe.msgprint(__('Error: ' + (r.message ? r.message.message : "No response")));
                        }
                    }
                });
            });
        }
    }
});

frappe.call({
    method: "one_third_rule", // Full path needed
    args: {},
    callback: function(r) {
        if (r.message && r.message.status === "success") {
            let breaches = r.message.breaches;
            if (breaches.length === 0) {
                frappe.msgprint("✅ All employees meet the 1/3 Rule.");
            } else {
                let rows = breaches.map(b => 
                    `<tr>
                        <td>${b.employee}</td>
                        <td>${b.employee_name}</td>
                        <td>${frappe.format(b.gross_pay, {fieldtype: 'Currency'})}</td>
                        <td>${frappe.format(b.net_pay, {fieldtype: 'Currency'})}</td>
                        <td>${frappe.format(b.threshold, {fieldtype: 'Currency'})}</td>
                        <td>${frappe.format(b.shortfall, {fieldtype: 'Currency'})}</td>
                        <td>${b.payroll_entry || '-'}</td>
                    </tr>`
                ).join("");
                let html = `
                    <h4>⚠️ Employees Breaching 1/3 Rule (${breaches.length})</h4>
                    <table class="table table-bordered table-striped">
                        <thead>
                            <tr>
                                <th>Employee</th>
                                <th>Name</th>
                                <th>Gross Pay</th>
                                <th>Net Pay</th>
                                <th>2/3 Threshold</th>
                                <th>Shortfall</th>
                                <th>Payroll Entry</th>
                            </tr>
                        </thead>
                        <tbody>${rows}</tbody>
                    </table>`;
                frappe.msgprint({ 
                    title: "1/3 Rule Violations", 
                    message: html, 
                    wide: true 
                });
            }
        } else {
            frappe.msgprint({
                title: "Error",
                indicator: "red",
                message: r.message?.error || r.exc || "Unknown error occurred"
            });
        }
    },
    error: function(r) {
        frappe.msgprint({
            title: "Error",
            indicator: "red",
            message: "Failed to execute 1/3 rule check. Please check console for details."
        });
        console.error("1/3 Rule Error:", r);
    }
});

frappe.listview_settings['Salary Slip'] = {
    onload: function(listview) {
        listview.page.add_inner_button(__('Check 1/3 Rule'), function() {
            let selected = listview.get_checked_items();

            if (selected.length === 0) {
                frappe.msgprint(__('Please select at least one Salary Slip'));
                return;
            }

            let slip_names = selected.map(item => item.name);

            frappe.call({
                method: "one_third_rule",
                args: {
                    salary_slips: JSON.stringify(slip_names)
                },
                callback: function(r) {
                    if (r.message && r.message.status === "success") {
                        let breaches = r.message.breaches;
                        let all_slips = r.message.all_slips;

                        if (breaches.length === 0) {
                            frappe.msgprint(__("All selected employees meet the 1/3 Rule."));
                        } else {
                            let rows = breaches.map(b => 
                                `<tr>
                                    <td><a href="/app/salary-slip/${b.salary_slip}">${b.employee}</a></td>
                                    <td>${b.employee_name}</td>
                                    <td>${frappe.format(b.gross_pay, {fieldtype: 'Currency'})}</td>
                                    <td>${frappe.format(b.net_pay, {fieldtype: 'Currency'})}</td>
                                    <td>${frappe.format(b.threshold, {fieldtype: 'Currency'})}</td>
                                    <td>${frappe.format(b.shortfall, {fieldtype: 'Currency'})}</td>
                                </tr>`
                            ).join("");

                            let html = `
                                <div style="margin-bottom: 15px;">
                                    <strong>Total Checked:</strong> ${selected.length} | 
                                    <strong style="color: red;">Violations:</strong> ${breaches.length}
                                </div>
                                <table class="table table-bordered table-striped">
                                    <thead>
                                        <tr>
                                            <th>Employee</th>
                                            <th>Name</th>
                                            <th>Gross Pay</th>
                                            <th>Net Pay</th>
                                            <th>1/3 Threshold</th>
                                            <th>Shortfall</th>
                                        </tr>
                                    </thead>
                                    <tbody>${rows}</tbody>
                                </table>`;

                            frappe.msgprint({ 
                                title: __("1/3 Rule Violations"), 
                                message: html, 
                                wide: true 
                            });
                        }
                    } else {
                        frappe.msgprint(__("Error: ") + (r.message?.error || "Unknown error"));
                    }
                },
                error: function(r) {
                    frappe.msgprint(__("Failed to check 1/3 rule. Check console."));
                    console.error(r);
                }
            });
        });
    }
};

frappe.ui.form.on("Salary Structure Assignment", {
    refresh(frm) {
        if (frappe.user_roles.includes("Payroll manager (non-management)")) {
            frm.set_query("employee", () => {
                return {
                    filters: {
                        employment_type: ["in", ["Seasonal", "Permanent", "Annual Contract"]]
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Payroll Entry', {
    refresh: function(frm) {
        // Override the "Submit Salary Slip" button
        if (frm.doc.docstatus === 1 && frm.doc.salary_slips_submitted === 0) {
            // Remove the standard button
            frm.remove_custom_button(__('Submit Salary Slip'));

            // Add our custom button with validation
            frm.add_custom_button(__('Submit Salary Slip'), function() {

                // Show loading indicator
                frappe.show_alert({
                    message: __('Validating 1/3 rule...'),
                    indicator: 'blue'
                }, 3);

                // Validate 1/3 rule before submission
                frappe.call({
                    method: 'validate_payroll_one_third_rule',
                    args: {
                        payroll_entry: frm.doc.name
                    },
                    callback: function(r) {
                        if (r.message && r.message.status === 'violation') {
                            // Block submission
                            frappe.msgprint({
                                title: __('Cannot Submit Salary Slips'),
                                message: __('Cannot submit salary slips due to 1/3 rule violations'),
                                indicator: 'red'
                            });
                        } else if (r.message && r.message.status === 'success') {
                            // All clear - proceed with submission using the standard method
                            frm.call('submit_salary_slips').then(() => {
                                frm.reload_doc();
                                frappe.show_alert({
                                    message: __('Salary slips submitted successfully'),
                                    indicator: 'green'
                                }, 5);
                            });
                        } else if (r.message && r.message.status === 'no_slips') {
                            frappe.msgprint(__('No draft salary slips found for this payroll entry'));
                        }
                    },
                    error: function(r) {
                        frappe.msgprint(__('Error validating 1/3 rule. Please try again.'));
                    }
                });

            }).addClass('btn-primary');
        }
    }
});

frappe.ui.form.on("Employee", {
