// Custom Script → DocType: Employee → List View
frappe.listview_settings["Employee"] = {
    add_fields: ["status", "employment_type", "branch", "department", "designation", "image"],

    onload: function(listview) {
        apply_restrictions(listview);
    },

    refresh: function(listview) {
        apply_restrictions(listview);
    },

    get_indicator: function(doc) {
        const colors = {
            "Active": ["green", "status,=,Active"],
            "Inactive": ["red", "status,=,Inactive"],
            "Left": ["gray", "status,=,Left"],
            "Suspended": ["orange", "status,=,Suspended"]
        };
        return colors[doc.status] ? [__(doc.status), ...colors[doc.status]] : [doc.status, "gray"];
    }
};

function apply_restrictions(listview) {
    // 1. Get current user roles
    const user_roles = frappe.user_roles || [];

    // 2. Define who has full access
    const full_access_roles = ["System Manager", "HR Manager", "Payroll Manager (Management & non_management)"];
    const has_full_access = full_access_roles.some(role => user_roles.includes(role));

    // 3. Specific allowed users
    const allowed_emails = [
        "peter.ngotho@tambuzi.co.ke",
        "christine.shikuku@tambuzi.co.ke"
    ];
    const is_allowed_email = allowed_emails.includes(frappe.session.user);

    // 4. Is this a restricted user?
    const is_restricted = !has_full_access && !is_allowed_email;

    // Only enforce employment type for restricted users
    if (is_restricted) {
        // 5. Get current filters
        const existing_filters = listview.filter_area.get();

        // 6. Check if employment type filter exists
        const has_employment_filter = existing_filters.some(f => 
            f[1] === "employment_type" && f[2] === "in"
        );

        // 7. Re-apply if missing (user removed it)
        if (!has_employment_filter) {
            // Save all other user filters
            const user_filters = existing_filters.filter(f => 
                !(f[1] === "employment_type")
            );

            listview.filter_area.clear();

            // Add mandatory employment type filter
            listview.filter_area.add([
                ["Employee", "employment_type", "in", ["Permanent", "Seasonal", "Annual Contract"]]
            ]);

            // Re-add user's custom filters
            user_filters.forEach(filter => {
                listview.filter_area.add([filter]);
            });
        }


        // 9. Setup continuous monitoring (only once)
        if (!listview._filter_watcher) {
            listview._filter_watcher = setInterval(() => {
                apply_restrictions(listview);
            }, 500);
        }
    }
}

frappe.ui.form.on('Disciplinary', {
    // ===== AUTO-POPULATE WARNING LEVEL =====
    employee(frm) {
        if (!frm.doc.employee) return;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Disciplinary",
                filters: { 
                    employee: frm.doc.employee,
                    docstatus: 1
                },
                fields: ["warning_level"]
            },
            callback(r) {
                let count = r.message ? r.message.length : 0;

                let next_level = "First Warning";
                if (count === 1) next_level = "Second Warning";
                else if (count === 2) next_level = "Final Warning";
                else if (count >= 3) next_level = "Summary Dismissal";

                frm.set_value("warning_level", next_level);
            }
        });
    },

    // ===== GROSS MISCONDUCT CHECKBOX =====
    custom_is_gross_misconduct(frm) {
        if (frm.doc.custom_is_gross_misconduct) {
            frm.set_value("warning_level", "Summary Dismissal");
        }
    },

    // ===== DYNAMIC BUTTONS BASED ON WARNING LEVEL =====
    refresh(frm) {
        // Clear existing custom buttons
        frm.page.clear_menu();

        if (frm.doc.docstatus === 1) {
            let warning_level = frm.doc.warning_level;

            // ===== SUMMARY DISMISSAL: Only Summary Dismissal button =====
            if (warning_level === "Summary Dismissal") {
                frm.add_custom_button('Download Summary Dismissal', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Summary Dismissal Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }

            // ===== FINAL WARNING: Two buttons (Warning Letter + Summary Dismissal) =====
            else if (warning_level === "Final Warning") {
                frm.add_custom_button('Download Warning Letter', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Disciplinary Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');

                frm.add_custom_button('Download Summary Dismissal', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Summary Dismissal Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }

            // ===== OTHER WARNINGS: Standard Warning Letter button =====
            else {
                frm.add_custom_button('Download Warning Letter', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Disciplianry Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }
        }
    }
});

